#!/usr/bin/env dotnet script
#r "nuget: Microsoft.Agents.AI, 1.6.2"
#r "nuget: Microsoft.Extensions.AI, 10.5.1"
#r "nuget: Microsoft.Extensions.AI.Abstractions, 10.6.0"

using System;
using System.Reflection;
using System.Linq;

var agentsAssembly = typeof(Microsoft.Agents.AI.Agent).Assembly;
var extensionsAssembly = typeof(Microsoft.Extensions.AI.ChatClient).Assembly;
var abstractionsAssembly = typeof(Microsoft.Extensions.AI.Abstractions.ChatOptions).Assembly;

// Find ChatClientAgent
var chatClientAgentType = agentsAssembly.GetType("Microsoft.Agents.AI.ChatClientAgent");
if (chatClientAgentType != null)
{
    Console.WriteLine("=== ChatClientAgent ===");
    Console.WriteLine($"Full Name: {chatClientAgentType.FullName}");

    var constructors = chatClientAgentType.GetConstructors(BindingFlags.Public | BindingFlags.Instance);
    Console.WriteLine($"\nConstructors ({constructors.Length}):");
    foreach (var ctor in constructors)
    {
        var @params = ctor.GetParameters();
        var paramStr = string.Join(", ", @params.Select(p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  public ChatClientAgent({paramStr})");
    }

    var methods = chatClientAgentType.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly);
    Console.WriteLine($"\nPublic Methods:");
    foreach (var method in methods.Where(m => !m.IsSpecialName).OrderBy(m => m.Name))
    {
        var @params = method.GetParameters();
        var paramStr = string.Join(", ", @params.Select(p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  {method.ReturnType.Name} {method.Name}({paramStr})");
    }
}

// Find other Agent types
Console.WriteLine("\n=== Other Agent Types ===");
var agentTypes = agentsAssembly.GetTypes()
    .Where(t => t.Name.Contains("Agent") && t.IsPublic && !t.IsAbstract)
    .OrderBy(t => t.Name);

foreach (var type in agentTypes)
{
    Console.WriteLine($"{type.FullName}");
}

// Find AIFunction and related
Console.WriteLine("\n=== AI Function Types ===");
var funcTypes = abstractionsAssembly.GetTypes()
    .Where(t => t.Name.Contains("Function") || t.Name.Contains("Tool"))
    .Where(t => t.IsPublic)
    .OrderBy(t => t.Name);

foreach (var type in funcTypes)
{
    Console.WriteLine($"{type.FullName}");
}

// Find invoke methods and options
Console.WriteLine("\n=== Agent Invoke Methods ===");
if (chatClientAgentType != null)
{
    var invokeMethods = chatClientAgentType.GetMethods()
        .Where(m => m.Name.Contains("Invoke") || m.Name.Contains("invoke"))
        .OrderBy(m => m.Name);

    foreach (var method in invokeMethods)
    {
        var @params = method.GetParameters();
        var paramStr = string.Join(", ", @params.Select(p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  {method.ReturnType.Name} {method.Name}({paramStr})");
    }
}

// Find AgentInvokeOptions
Console.WriteLine("\n=== Options Types ===");
var optionsTypes = agentsAssembly.GetTypes()
    .Where(t => t.Name.Contains("Options") || t.Name.Contains("Settings"))
    .Where(t => t.IsPublic)
    .OrderBy(t => t.Name);

foreach (var type in optionsTypes)
{
    Console.WriteLine($"{type.FullName}");
    var props = type.GetProperties(BindingFlags.Public | BindingFlags.Instance);
    foreach (var prop in props.Take(5))
    {
        Console.WriteLine($"  {prop.PropertyType.Name} {prop.Name}");
    }
}

Console.WriteLine("\n=== Complete ===");
EOF
