using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;

// 1. Create a ChatClientAgent
var chatClient = new OpenAIClient(...).AsChatClient("gpt-4");
var agent = new ChatClientAgent(
    chatClient,
    instructions: "You are a helpful assistant",
    name: "Research Agent",
    description: "An agent that researches topics",
    tools: new List<AITool> { /* AIFunctions converted to tools */ }
);

// 2. Define a tool/function
var searchFunction = AIFunctionFactory.Create(
    (string query) => SearchAsync(query),
    name: "search",
    description: "Search for information"
);

// 3. Create a session
var session = await agent.CreateSessionAsync();

// 4. Run the agent with options
var options = new ChatClientAgentRunOptions(
    new ChatOptions
    {
        Tools = new List<AITool> { searchFunction },
        MaxOutputTokens = 1000,
        Temperature = 0.7
    }
);

var response = await agent.RunAsync("What is X?", session, options);

// 5. Access the response
foreach (var message in response.Messages)
{
    Console.WriteLine($"{message.Role}: {message.Content}");
}
```

