using System.ComponentModel;
using System.Text;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using OpenAI;

// ── Configuration ──────────────────────────────────────────────────────────────

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string ModelId = "gpt-4o-mini-2024-07-18";

// ── Service registration ───────────────────────────────────────────────────────

var services = new ServiceCollection();

services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));

services.AddChatClient(builder => builder
    .UseOpenAIChatClient(ModelId, new OpenAIClient(apiKey)));

var sp = services.BuildServiceProvider();
var chatClient = sp.GetRequiredService<IChatClient>();
var loggerFactory = sp.GetRequiredService<ILoggerFactory>();

// ── Tools ──────────────────────────────────────────────────────────────────────

var researchTools = new ResearchTools();

var tools = new AITool[]
{
    AIFunctionFactory.Create(researchTools.SearchWebAsync,
        name: "search_web",
        description: "Search the web for information on a given query. Returns a list of result snippets."),
    AIFunctionFactory.Create(researchTools.SaveNote,
        name: "save_note",
        description: "Save a research note with a title and body for later reference."),
    AIFunctionFactory.Create(researchTools.GetNotes,
        name: "get_notes",
        description: "Retrieve all saved research notes collected so far."),
};

// ── Agent setup ────────────────────────────────────────────────────────────────

const string Instructions = """
    You are a Research Agent. Your goal is to thoroughly research the topic
    the user provides and produce a concise, well-structured summary.

    Workflow:
    1. Break the topic into 2-3 focused search queries.
    2. For each query, call `search_web` to gather information.
    3. After each search, call `save_note` to record key findings with a
       descriptive title.
    4. Once you have enough material, call `get_notes` to review everything.
    5. Synthesize the notes into a final summary with sections, key facts,
       and source references.

    Always cite which search results informed each section.
    """;

var agent = new ChatClientAgent(
    chatClient,
    instructions: Instructions,
    name: "ResearchAgent",
    description: "Researches a topic using web search and note-taking tools",
    tools: tools,
    loggerFactory: loggerFactory);

// ── Run the agent ──────────────────────────────────────────────────────────────

Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       Research Agent (MAF + MEAI)    ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine();
Console.WriteLine($"Researching: {topic}");
Console.WriteLine(new string('─', 60));

var session = new ChatClientAgentSession();

var runOptions = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 4096,
    },
};

await foreach (var update in agent.RunStreamingAsync(topic, session, runOptions))
{
    if (update.Content is { Length: > 0 })
    {
        Console.Write(update.Content);
    }
}

Console.WriteLine();
Console.WriteLine(new string('─', 60));
Console.WriteLine($"Research complete. {researchTools.NoteCount} note(s) saved during research.");

// ── Tool implementations ───────────────────────────────────────────────────────

sealed class ResearchTools
{
    private static readonly HttpClient s_http = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
            { "Accept", "application/json" },
        },
    };

    private readonly List<ResearchNote> _notes = [];

    public int NoteCount => _notes.Count;

    /// <summary>Searches the web using DuckDuckGo Instant Answer API.</summary>
    public async Task<string> SearchWebAsync(string query)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var json = await s_http.GetStringAsync(url);

            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new StringBuilder();

            // Abstract / main answer
            var abstractText = root.GetProperty("AbstractText").GetString();
            var abstractSource = root.GetProperty("AbstractSource").GetString();
            var abstractUrl = root.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.AppendLine($"[Source: {abstractSource}] {abstractText}");
                results.AppendLine($"  URL: {abstractUrl}");
                results.AppendLine();
            }

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                var count = 0;
                foreach (var item in topics.EnumerateArray())
                {
                    if (count >= 5) break;
                    var text = item.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    var firstUrl = item.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;
                    if (!string.IsNullOrWhiteSpace(text))
                    {
                        results.AppendLine($"- {text}");
                        if (!string.IsNullOrWhiteSpace(firstUrl))
                            results.AppendLine($"  URL: {firstUrl}");
                        count++;
                    }
                }
            }

            var output = results.ToString();
            return string.IsNullOrWhiteSpace(output)
                ? $"No detailed results found for \"{query}\". Try rephrasing."
                : output;
        }
        catch (Exception ex)
        {
            return $"Search failed for \"{query}\": {ex.Message}";
        }
    }

    /// <summary>Saves a research note for later synthesis.</summary>
    public string SaveNote(string title, string body)
    {
        _notes.Add(new ResearchNote(title, body, DateTime.UtcNow));
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    /// <summary>Gets all research notes collected so far.</summary>
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
        {
            var n = _notes[i];
            sb.AppendLine($"--- Note #{i + 1}: {n.Title} ({n.Timestamp:u}) ---");
            sb.AppendLine(n.Body);
            sb.AppendLine();
        }

        Console.WriteLine($"  📋 Returning {_notes.Count} note(s)");
        return sb.ToString();
    }
}

record ResearchNote(string Title, string Body, DateTime Timestamp);

