+    .UseOpenAIChatClient(ModelId, new OpenAIClient(apiKey)));
+
+var sp = services.BuildServiceProvider();
+var chatClient = sp.GetRequiredService<IChatClient>();
+var loggerFactory = sp.GetRequiredService<ILoggerFactory>();
+
+// ── Tools ──────────────────────────────────────────────────────────────────────
+
+var researchTools = new ResearchTools();
+
+var tools = new AITool[]
+{
+    AIFunctionFactory.Create(researchTools.SearchWebAsync,
+        name: "search_web",
+        description: "Search the web for information on a given query. Returns a list of result snippets."),
+    AIFunctionFactory.Create(researchTools.SaveNote,
+        name: "save_note",
+        description: "Save a research note with a title and body for later reference."),
+    AIFunctionFactory.Create(researchTools.GetNotes,
+        name: "get_notes",
+        description: "Retrieve all saved research notes collected so far."),
+};
+
+// ── Agent setup ────────────────────────────────────────────────────────────────
+
+const string Instructions = """
+    You are a Research Agent. Your goal is to thoroughly research the topic
+    the user provides and produce a concise, well-structured summary.
+
+    Workflow:
+    1. Break the topic into 2-3 focused search queries.
+    2. For each query, call `search_web` to gather information.
+    3. After each search, call `save_note` to record key findings with a
+       descriptive title.
+    4. Once you have enough material, call `get_notes` to review everything.
+    5. Synthesize the notes into a final summary with sections, key facts,
+       and source references.
+
+    Always cite which search results informed each section.
+    """;
+
+var agent = new ChatClientAgent(
+    chatClient,
+    instructions: Instructions,
+    name: "ResearchAgent",
+    description: "Researches a topic using web search and note-taking tools",
+    tools: tools,
+    loggerFactory: loggerFactory);
