+            { "User-Agent", "ResearchAgent/1.0" },
+            { "Accept", "application/json" },
+        },
+    };
+
+    private readonly List<ResearchNote> _notes = [];
+
+    public int NoteCount => _notes.Count;
+
+    /// <summary>Searches the web using DuckDuckGo Instant Answer API.</summary>
+    public async Task<string> SearchWebAsync(string query)
+    {
+        Console.WriteLine($"  🔍 Searching: \"{query}\"");
+
+        try
+        {
+            var encoded = Uri.EscapeDataString(query);
+            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
+            var json = await s_http.GetStringAsync(url);
+
+            using var doc = JsonDocument.Parse(json);
+            var root = doc.RootElement;
+
+            var results = new StringBuilder();
+
+            // Abstract / main answer
+            var abstractText = root.GetProperty("AbstractText").GetString();
+            var abstractSource = root.GetProperty("AbstractSource").GetString();
+            var abstractUrl = root.GetProperty("AbstractURL").GetString();
+            if (!string.IsNullOrWhiteSpace(abstractText))
+            {
+                results.AppendLine($"[Source: {abstractSource}] {abstractText}");
+                results.AppendLine($"  URL: {abstractUrl}");
+                results.AppendLine();
+            }
+
+            // Related topics
+            if (root.TryGetProperty("RelatedTopics", out var topics))
+            {
+                var count = 0;
+                foreach (var item in topics.EnumerateArray())
+                {
+                    if (count >= 5) break;
+                    var text = item.TryGetProperty("Text", out var t) ? t.GetString() : null;
+                    var firstUrl = item.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;
+                    if (!string.IsNullOrWhiteSpace(text))
+                    {
+                        results.AppendLine($"- {text}");
+                        if (!string.IsNullOrWhiteSpace(firstUrl))
+                            results.AppendLine($"  URL: {firstUrl}");
+                        count++;
+                    }
+                }
+            }
+
+            var output = results.ToString();
+            return string.IsNullOrWhiteSpace(output)
+                ? $"No detailed results found for \"{query}\". Try rephrasing."
+                : output;
+        }
+        catch (Exception ex)
+        {
+            return $"Search failed for \"{query}\": {ex.Message}";
+        }
+    }
+
